const result = $input.first().json;

if (!result.patient_id) {
  return [{ json: { resultado: 'Paciente não encontrado no cadastro. Pode ser um novo paciente.' } }];
}

let resultado = `Paciente encontrado:\n`;
resultado += `👤 ${result.name}\n`;
resultado += `📱 ${result.phone}\n`;
if (result.birth_date) resultado += `🎂 ${new Date(result.birth_date).toLocaleDateString('pt-BR')}\n`;
if (result.health_insurance) resultado += `🏥 Convênio: ${result.health_insurance}\n`;
if (result.allergies && result.allergies.length > 0) resultado += `⚠️ Alergias: ${result.allergies.join(', ')}\n`;
if (result.medical_conditions && result.medical_conditions.length > 0) resultado += `🩺 Condições: ${result.medical_conditions.join(', ')}\n`;
resultado += `📊 Total de consultas: ${result.total_appointments}\n`;
if (result.active_treatments > 0) resultado += `🔄 Tratamentos ativos: ${result.active_treatments}\n`;
if (result.last_appointment) resultado += `📅 Última consulta: ${new Date(result.last_appointment).toLocaleDateString('pt-BR')}\n`;

return [{ json: { resultado, patient_id: result.patient_id } }];
